################################################################################
# Infrastructure as Code — Service RAG (Terraform >= 1.7, AWS provider ~> 5.x)
# Composants : EKS (compute), RDS PostgreSQL + pgvector (VectorStore),
#              OpenSearch (LexicalIndex BM25), Secrets Manager, ECR, IRSA.
# Etat distant recommande : S3 + DynamoDB lock (non montre).
################################################################################

terraform {
  required_version = ">= 1.7"
  required_providers {
    aws = { source = "hashicorp/aws", version = "~> 5.50" }
  }
}

provider "aws" {
  region = var.region
}

variable "region"      { type = string, default = "eu-west-3" }
variable "project"     { type = string, default = "rag-service" }
variable "environment" { type = string, default = "prod" }

locals {
  name = "${var.project}-${var.environment}"
  tags = { Project = var.project, Env = var.environment, ManagedBy = "terraform" }
}

# --- Reseau : VPC dedie (3 AZ, subnets prives pour data/compute) -------------
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.8"

  name = "${local.name}-vpc"
  cidr = "10.40.0.0/16"

  azs             = ["${var.region}a", "${var.region}b", "${var.region}c"]
  private_subnets = ["10.40.1.0/24", "10.40.2.0/24", "10.40.3.0/24"]
  public_subnets  = ["10.40.101.0/24", "10.40.102.0/24", "10.40.103.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = true   # FinOps : 1 seul NAT (~32 USD/mois). HA -> passer a false.
  enable_dns_hostnames = true
  tags = local.tags
}

# --- EKS : cluster + node group managed (compute du service RAG) -------------
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 20.0"

  cluster_name    = "${local.name}-eks"
  cluster_version = "1.30"

  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets

  enable_irsa                              = true   # IRSA : pods -> IAM sans secrets
  cluster_endpoint_public_access           = true
  cluster_endpoint_public_access_cidrs     = ["0.0.0.0/0"]  # A restreindre au VPN entreprise

  eks_managed_node_groups = {
    default = {
      # FinOps : Spot pour stateless RAG, ScaledToZero possible hors heures ouvrees
      instance_types = ["m6i.large"]
      capacity_type  = "SPOT"
      min_size       = 2
      max_size       = 6
      desired_size   = 2
    }
  }
  tags = local.tags
}

# --- RDS PostgreSQL 16 + extension pgvector (VectorStore) --------------------
resource "aws_db_subnet_group" "rag" {
  name       = "${local.name}-db-subnets"
  subnet_ids = module.vpc.private_subnets
  tags       = local.tags
}

resource "aws_security_group" "rds" {
  name   = "${local.name}-rds-sg"
  vpc_id = module.vpc.vpc_id
  ingress {
    from_port       = 5432
    to_port         = 5432
    protocol        = "tcp"
    security_groups = [module.eks.node_security_group_id]  # acces depuis les pods uniquement
  }
  egress { from_port = 0, to_port = 0, protocol = "-1", cidr_blocks = ["0.0.0.0/0"] }
  tags = local.tags
}

resource "aws_db_instance" "pgvector" {
  identifier             = "${local.name}-pg"
  engine                 = "postgres"
  engine_version         = "16.3"
  instance_class         = "db.t4g.medium"   # FinOps : Graviton, ~50 USD/mois
  allocated_storage      = 50
  storage_encrypted      = true
  db_name                = "ragdb"
  username               = "ragadmin"
  manage_master_user_password = true          # secret gere par Secrets Manager
  db_subnet_group_name   = aws_db_subnet_group.rag.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  multi_az               = true
  backup_retention_period = 7
  skip_final_snapshot    = false
  final_snapshot_identifier = "${local.name}-final"
  tags = local.tags
  # NB : activer l'extension pgvector via migration applicative : CREATE EXTENSION vector;
}

# --- OpenSearch : index lexical BM25 (LexicalIndex) -------------------------
resource "aws_opensearch_domain" "lexical" {
  domain_name    = "${local.name}-os"
  engine_version = "OpenSearch_2.13"

  cluster_config {
    instance_type          = "t3.small.search"  # FinOps dev/prod legere ; scaler en prod chargee
    instance_count         = 2
    zone_awareness_enabled = true
    zone_awareness_config { availability_zone_count = 2 }
  }
  ebs_options { ebs_enabled = true, volume_size = 20, volume_type = "gp3" }
  encrypt_at_rest { enabled = true }
  node_to_node_encryption { enabled = true }
  domain_endpoint_options { enforce_https = true }
  vpc_options {
    subnet_ids         = slice(module.vpc.private_subnets, 0, 2)
    security_group_ids = [aws_security_group.rds.id]
  }
  tags = local.tags
}

# --- ECR : registre de l'image applicative ----------------------------------
resource "aws_ecr_repository" "rag" {
  name                 = var.project
  image_tag_mutability = "IMMUTABLE"
  image_scanning_configuration { scan_on_push = true }
  tags = local.tags
}

# --- Secrets Manager : cle reranker / LLM judge (evals) ---------------------
resource "aws_secretsmanager_secret" "llm" {
  name = "${local.name}/llm-api-key"
  tags = local.tags
}

output "eks_cluster_name" { value = module.eks.cluster_name }
output "rds_endpoint"     { value = aws_db_instance.pgvector.endpoint }
output "opensearch_endpoint" { value = aws_opensearch_domain.lexical.endpoint }
output "ecr_repo_url"     { value = aws_ecr_repository.rag.repository_url }

# --- Estimation cout mensuel (eu-west-3, ordre de grandeur) -----------------
# EKS control plane ........ ~73 USD
# 2x m6i.large Spot ........ ~70 USD
# RDS db.t4g.medium MultiAZ  ~100 USD
# OpenSearch 2x t3.small ... ~60 USD
# NAT GW single ............ ~32 USD
# TOTAL ESTIME ............. ~335 USD/mois (hors trafic LLM externe)
